func openPushoverLocalDB(ctx context.Context, dbPath string) (*sql.DB, error) {
	if dbPath == "" {
		dbPath = defaultDBPath("pushover-pp-cli")
	}
	if err := os.MkdirAll(filepath.Dir(dbPath), 0o755); err != nil {
		return nil, fmt.Errorf("creating local db directory: %w", err)
	}
	// PATCH(pr511-db-file-perms): the local history/inbox DB stores
	// notification metadata and message previews; sql.Open is lazy and
	// would otherwise let the file land at default-umask 0o644 next to
	// sensitive content. Pre-touch at 0o600 before the driver opens,
	// then chmod the file + WAL/SHM sidecars after migration.
	restrictLocalDBFilePermissions(dbPath)
	db, err := sql.Open("sqlite", dbPath+"?_journal_mode=WAL&_synchronous=NORMAL&_busy_timeout=5000&_foreign_keys=ON")
	if err != nil {
		return nil, fmt.Errorf("opening local db: %w", err)
	}
	if err := migratePushoverLocalDB(ctx, db); err != nil {
		db.Close()
		return nil, err
	}
	restrictLocalDBFilePermissions(dbPath)
	return db, nil
}

// restrictLocalDBFilePermissions mirrors store.restrictDBFilePermissions
// (unexported there) for the CLI-package local DB. Kept inline rather
// than promoting the store helper to public API: the two databases have
// different lifecycles (the store DB is the main app DB; this one is the
// novel-history ledger) and we don't want to couple their open paths.
func restrictLocalDBFilePermissions(path string) {
	if f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY, 0o600); err == nil {
		_ = f.Close()
	}
	for _, suffix := range []string{"", "-wal", "-shm"} {
		_ = os.Chmod(path+suffix, 0o600)
	}
}

func migratePushoverLocalDB(ctx context.Context, db *sql.DB) error {
	stmts := []string{
		`CREATE TABLE IF NOT EXISTS notification_history (
			id INTEGER PRIMARY KEY AUTOINCREMENT,
			created_at TEXT NOT NULL,
			command TEXT NOT NULL,
			request_id TEXT,
			receipt TEXT,
			status_code INTEGER NOT NULL,
			success INTEGER NOT NULL,
			priority INTEGER NOT NULL,
			title TEXT,
			message_preview TEXT NOT NULL,
			recipient_hash TEXT,
			device TEXT,
			sound TEXT,
			url TEXT,
			response JSON
		)`,
		`CREATE INDEX IF NOT EXISTS idx_notification_history_created ON notification_history(created_at)`,
		`CREATE INDEX IF NOT EXISTS idx_notification_history_receipt ON notification_history(receipt)`,
		`CREATE TABLE IF NOT EXISTS inbox_messages (
			id TEXT PRIMARY KEY,
			synced_at TEXT NOT NULL,
			received_at TEXT,
			title TEXT,
			message_preview TEXT,
			app TEXT,
			priority INTEGER
		)`,
		`CREATE INDEX IF NOT EXISTS idx_inbox_messages_synced ON inbox_messages(synced_at)`,
	}
	for _, stmt := range stmts {
		if _, err := db.ExecContext(ctx, stmt); err != nil {
			return fmt.Errorf("migrating pushover local db: %w", err)
		}
	}
	return nil
}

func recordNotificationHistory(ctx context.Context, dbPath string, record notificationHistoryRecord) (int64, error) {
	db, err := openPushoverLocalDB(ctx, dbPath)
	if err != nil {
		return 0, err
	}
	defer db.Close()
	if record.CreatedAt == "" {
		record.CreatedAt = time.Now().UTC().Format(time.RFC3339)
	}
	responseJSON, err := json.Marshal(record.Response)
	if err != nil {
		return 0, err
	}
	result, err := db.ExecContext(ctx, `INSERT INTO notification_history
		(created_at, command, request_id, receipt, status_code, success, priority, title, message_preview, recipient_hash, device, sound, url, response)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
		record.CreatedAt, record.Command, record.RequestID, record.Receipt, record.StatusCode, boolToInt(record.Success),
		record.Priority, record.Title, record.MessagePreview, record.RecipientHash, record.Device, record.Sound, record.URL, string(responseJSON),
	)
	if err != nil {
		return 0, fmt.Errorf("recording notification history: %w", err)
	}
	return result.LastInsertId()
}

func listNotificationHistory(ctx context.Context, dbPath, since string, limit int) ([]notificationHistoryRecord, error) {
	db, err := openPushoverLocalDB(ctx, dbPath)
	if err != nil {
		return nil, err
	}
	defer db.Close()
	sinceTS, err := parseHistorySince(since)
	if err != nil {
		return nil, err
	}
	if limit <= 0 || limit > 500 {
		limit = 25
	}
	rows, err := db.QueryContext(ctx, `SELECT id, created_at, command, request_id, receipt, status_code, success, priority, title, message_preview, recipient_hash, device, sound, url, response
		FROM notification_history
		WHERE (? = '' OR created_at >= ?)
		ORDER BY id DESC
		LIMIT ?`, sinceTS, sinceTS, limit)
	if err != nil {
		return nil, fmt.Errorf("listing notification history: %w", err)
	}
	defer rows.Close()
	records := []notificationHistoryRecord{}
	for rows.Next() {
		record, err := scanNotificationHistory(rows)
		if err != nil {
			return nil, err
		}
		records = append(records, record)
	}
	return records, rows.Err()
}

func getNotificationHistory(ctx context.Context, dbPath string, id int64) (notificationHistoryRecord, error) {
	db, err := openPushoverLocalDB(ctx, dbPath)
	if err != nil {
		return notificationHistoryRecord{}, err
	}
	defer db.Close()
	row := db.QueryRowContext(ctx, `SELECT id, created_at, command, request_id, receipt, status_code, success, priority, title, message_preview, recipient_hash, device, sound, url, response
		FROM notification_history WHERE id = ?`, id)
	record, err := scanNotificationHistory(row)
	if err == sql.ErrNoRows {
		return notificationHistoryRecord{}, notFoundErr(fmt.Errorf("history row %d not found", id))
	}
	return record, err
}

type scanner interface {
	Scan(dest ...any) error
}

func scanNotificationHistory(row scanner) (notificationHistoryRecord, error) {
	var record notificationHistoryRecord
	var success int
	var requestID, receipt, title, recipientHash, device, sound, url, responseText sql.NullString
	if err := row.Scan(&record.ID, &record.CreatedAt, &record.Command, &requestID, &receipt, &record.StatusCode,
		&success, &record.Priority, &title, &record.MessagePreview, &recipientHash, &device, &sound, &url, &responseText); err != nil {
		return notificationHistoryRecord{}, err
	}
	record.Success = success == 1
	record.RequestID = requestID.String
	record.Receipt = receipt.String
	record.Title = title.String
	record.RecipientHash = recipientHash.String
	record.Device = device.String
	record.Sound = sound.String
	record.URL = url.String
	if responseText.Valid && responseText.String != "" && responseText.String != "null" {
		_ = json.Unmarshal([]byte(responseText.String), &record.Response)
	}
	return record, nil
}

// PATCH(pr511-inbox-delete-through-int): returns highestNum (int64) alongside
// the string form so callers can send the numeric ID to update_highest_message.json
// without re-parsing. highestNum is -1 when no numeric message ID was seen.
func upsertInboxMessages(ctx context.Context, dbPath string, items []json.RawMessage) (int, string, int64, error) {
	db, err := openPushoverLocalDB(ctx, dbPath)
	if err != nil {
		return 0, "", -1, err
	}
	defer db.Close()
	tx, err := db.BeginTx(ctx, nil)
	if err != nil {
		return 0, "", -1, err
	}
	defer tx.Rollback()

	now := time.Now().UTC().Format(time.RFC3339)
	stored := 0
	highest := ""
	highestNum := int64(-1)
	for _, item := range items {
		record := inboxRecordFromRaw(item, now)
		if record.ID == "" {
			sum := sha256.Sum256(item)
			record.ID = hex.EncodeToString(sum[:12])
		}
		if n, err := strconv.ParseInt(record.ID, 10, 64); err == nil && n > highestNum {
			highestNum = n
			highest = record.ID
		} else if highest == "" {
			highest = record.ID
		}
		_, err := tx.ExecContext(ctx, `INSERT INTO inbox_messages
			(id, synced_at, received_at, title, message_preview, app, priority)
			VALUES (?, ?, ?, ?, ?, ?, ?)
			ON CONFLICT(id) DO UPDATE SET
				synced_at=excluded.synced_at,
				received_at=excluded.received_at,
				title=excluded.title,
				message_preview=excluded.message_preview,
				app=excluded.app,
				priority=excluded.priority`,
			record.ID, record.SyncedAt, record.ReceivedAt, record.Title, record.MessagePreview, record.App, record.Priority,
		)
		if err != nil {
			return 0, "", -1, fmt.Errorf("storing inbox message: %w", err)
		}
		stored++
	}
	if err := tx.Commit(); err != nil {
		return 0, "", -1, err
	}
	return stored, highest, highestNum, nil
}

func listInboxMessages(ctx context.Context, dbPath string, limit int) ([]inboxMessageRecord, error) {
	db, err := openPushoverLocalDB(ctx, dbPath)
	if err != nil {
		return nil, err
	}
	defer db.Close()
	if limit <= 0 || limit > 500 {
		limit = 25
	}
	rows, err := db.QueryContext(ctx, `SELECT id, synced_at, received_at, title, message_preview, app, priority
		FROM inbox_messages ORDER BY synced_at DESC, id DESC LIMIT ?`, limit)
	if err != nil {
		return nil, fmt.Errorf("listing inbox messages: %w", err)
	}
	defer rows.Close()
	records := []inboxMessageRecord{}
	for rows.Next() {
		var r inboxMessageRecord
		var receivedAt, title, messagePreview, app sql.NullString
		if err := rows.Scan(&r.ID, &r.SyncedAt, &receivedAt, &title, &messagePreview, &app, &r.Priority); err != nil {
			return nil, err
		}
		r.ReceivedAt = receivedAt.String
		r.Title = title.String
		r.MessagePreview = messagePreview.String
		r.App = app.String
		records = append(records, r)
	}
	return records, rows.Err()
}

func inboxRecordFromRaw(raw json.RawMessage, syncedAt string) inboxMessageRecord {
	var obj map[string]any
	_ = json.Unmarshal(raw, &obj)
	record := inboxMessageRecord{
		ID:             firstString(obj, "id", "message", "message_id"),
		SyncedAt:       syncedAt,
		Title:          firstString(obj, "title"),
		MessagePreview: messagePreview(firstString(obj, "message", "body", "text"), 160),
		App:            firstString(obj, "app", "application", "app_name"),
		Priority:       intFromAny(obj["priority"]),
	}
	if ts := int64FromAny(firstValue(obj, "date", "timestamp", "received_at")); ts > 0 {
		record.ReceivedAt = time.Unix(ts, 0).UTC().Format(time.RFC3339)
	} else {
		record.ReceivedAt = firstString(obj, "received_at", "created_at")
	}
	return record
}

func parseHistorySince(since string) (string, error) {
	since = strings.TrimSpace(since)
	if since == "" {
		return "", nil
	}
	if strings.HasSuffix(since, "d") {
		days, err := strconv.Atoi(strings.TrimSuffix(since, "d"))
		if err != nil || days < 0 {
			return "", fmt.Errorf("invalid --since value %q", since)
		}
		return time.Now().UTC().Add(-time.Duration(days) * 24 * time.Hour).Format(time.RFC3339), nil
	}
	if d, err := time.ParseDuration(since); err == nil {
		return time.Now().UTC().Add(-d).Format(time.RFC3339), nil
	}
	if ts, err := time.Parse(time.RFC3339, since); err == nil {
		return ts.UTC().Format(time.RFC3339), nil
	}
	return "", fmt.Errorf("invalid --since value %q: use a duration like 24h/7d or RFC3339", since)
}

func messagePreview(message string, max int) string {
	message = strings.Join(strings.Fields(message), " ")
	if max <= 0 || len([]rune(message)) <= max {
		return message
	}
	runes := []rune(message)
	return string(runes[:max]) + "..."
}

func hashForHistory(value string) string {
	if value == "" {
		return ""
	}
	sum := sha256.Sum256([]byte(value))
	return hex.EncodeToString(sum[:8])
}

func boolToInt(v bool) int {
	if v {
		return 1
	}
	return 0
}

func firstValue(obj map[string]any, keys ...string) any {
	for _, key := range keys {
		if v, ok := obj[key]; ok {
			return v
		}
	}
	return nil
}

func firstString(obj map[string]any, keys ...string) string {
	for _, key := range keys {
		if v, ok := obj[key]; ok {
			switch typed := v.(type) {
			case string:
				return typed
			case float64:
				return strconv.FormatInt(int64(typed), 10)
			case int:
				return strconv.Itoa(typed)
			}
		}
	}
	return ""
}

func intFromAny(v any) int {
	switch typed := v.(type) {
	case float64:
		return int(typed)
	case int:
		return typed
	case string:
		n, _ := strconv.Atoi(typed)
		return n
	default:
		return 0
	}
}

func int64FromAny(v any) int64 {
	switch typed := v.(type) {
	case float64:
		return int64(typed)
	case int64:
		return typed
	case int:
		return int64(typed)
	case string:
		n, _ := strconv.ParseInt(typed, 10, 64)
		return n
	default:
		return 0
	}
}
